def read_temperature():
    adc = ADC(Pin(34))
    adc.atten(ADC.ATTN_11DB)
    adc.width(ADC.WIDTH_12BIT)
    raw = adc.read()
    temperature = (raw / 4095.0) * 100.0
    return temperature

